function wallsAndGates(rooms) {
  if (!rooms.length || !rooms[0].length) return rooms;
  const rows = rooms.length;
  const cols = rooms[0].length;
  const INF = 2147483647;
  const queue = [];

  for (let r = 0; r < rows; r++) {
    for (let c = 0; c < cols; c++) {
      if (rooms[r][c] === 0) queue.push([r, c]);
    }
  }

  const dirs = [
    [-1, 0],
    [0, 1],
    [1, 0],
    [0, -1],
  ];

  while (queue.length) {
    const [r, c] = queue.shift();
    for (const [dr, dc] of dirs) {
      const nr = r + dr;
      const nc = c + dc;
      if (nr < 0 || nr >= rows || nc < 0 || nc >= cols) continue;
      if (rooms[nr][nc] !== INF) continue;
      rooms[nr][nc] = rooms[r][c] + 1;
      queue.push([nr, nc]);
    }
  }

  return rooms;
}

int[][] WallsAndGates(int[][] rooms)
{
    int rows = rooms.Length, cols = rooms[0].Length;
    var q = new Queue<(int r, int c)>();

    for (int r = 0; r < rows; r++)
    {
        for (int c = 0; c < cols; c++)
        {
            if (rooms[r][c] == 0) q.Enqueue((r, c));
        }
    }

    int[][] dirs = { new[] { 1, 0 }, new[] { -1, 0 }, new[] { 0, 1 }, new[] { 0, -1 } };

    while (q.Count > 0)
    {
        var (r, c) = q.Dequeue();
        foreach (var d in dirs)
        {
            int nr = r + d[0], nc = c + d[1];
            if (nr < 0 || nr >= rows || nc < 0 || nc >= cols) continue;
            if (rooms[nr][nc] != int.MaxValue) continue;

            rooms[nr][nc] = rooms[r][c] + 1;
            q.Enqueue((nr, nc));
        }
    }

    return rooms;
}

from collections import deque


def wallsAndGates(rooms):
    if not rooms or not rooms[0]:
        return rooms

    rows, cols = len(rooms), len(rooms[0])
    q = deque()

    for r in range(rows):
        for c in range(cols):
            if rooms[r][c] == 0:
                q.append((r, c))

    dirs = [(1, 0), (-1, 0), (0, 1), (0, -1)]

    while q:
        r, c = q.popleft()
        for dr, dc in dirs:
            nr, nc = r + dr, c + dc
            if nr < 0 or nr >= rows or nc < 0 or nc >= cols:
                continue
            if rooms[nr][nc] != 2147483647:
                continue
            rooms[nr][nc] = rooms[r][c] + 1
            q.append((nr, nc))

    return rooms

